INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0ad5b67f-be8c-4538-9ad0-3c97b9b0a476',
  '00000000-0000-0000-0000-000000000001',
  $escape$JAX Gradient Debugging — Hunting NaNs, Explosions, and Vanishing Flow$escape$,
  $escape$JAX's functional purity makes gradient debugging methodical. Use `jax.grad` with `has_aux=True` to return intermediate activations alongside gradients, then inspect norms with `jnp.linalg.norm`. NaN loss almost always traces back to `jnp.log(0)`, division by zero, or `jnp.sqrt` of negatives — use `jnp.nan_to_num` defensively or clamp inputs. For exploding gradients, global norm clipping is idiomatic: compute `optax.clip_by_global_norm(max_norm)` in your optimizer chain. Vanishing gradients are harder — add gradient norm logging inside your `jax.lax.scan` body by returning norms as auxiliary outputs. A critical JAX gotcha: `jit`-compiled functions silently swallow `print()` calls; use `jax.debug.print("{x}", x=grad_norm)` for runtime inspection inside JIT. To check gradient flow through a specific layer, temporarily wrap it with `jax.checkpoint` disabled and compare forward pass vs. backward pass norms. For NaN propagation tracing, set `JAX_DEBUG_NANS=1` in your environment — JAX will raise immediately at the offending operation rather than propagating silently.$escape$,
  $escape$import jax
import jax.numpy as jnp
import optax

# Enable NaN detection during debugging
import os
os.environ["JAX_DEBUG_NANS"] = "1"

def loss_fn(params, x, y):
    logits = model.apply(params, x)
    return jnp.mean(optax.softmax_cross_entropy_with_integer_labels(logits, y))

# Compute grads and inspect norms
grad_fn = jax.value_and_grad(loss_fn)
loss, grads = grad_fn(params, x_batch, y_batch)

leaf_norms = jax.tree.map(lambda g: jnp.linalg.norm(g), grads)
jax.debug.print("grad norms: {n}", n=leaf_norms)

# Clip exploding gradients in optimizer
optimizer = optax.chain(
    optax.clip_by_global_norm(1.0),
    optax.adam(1e-3)
)$escape$,
  $escape$python$escape$,
