INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3682e1ca-6cc6-43e4-943a-11ff0b703389',
  '00000000-0000-0000-0000-000000000001',
  $escape$JAX + Keras 3 — Functional API, Custom Layers, and Stateless Training Loops$escape$,
  $escape$Keras 3 runs natively on JAX by setting `KERAS_BACKEND=jax`, giving you Keras's full layer ecosystem inside JAX's functional execution model. The distinction between Sequential and Functional APIs matters more here: Sequential stacks layers linearly, while the Functional API builds a static computation graph — enabling skip connections, multi-input architectures, and cleaner XLA compilation traces.

Custom layers subclass `keras.Layer` and implement `call()`. JAX operations inside `call()` are pure by default — no hidden state mutations — which aligns directly with JAX's functional paradigm. Register trainable parameters with `self.add_weight()`; Keras exposes them as plain JAX arrays.

The key to custom training loops is `model.stateless_call(trainable_vars, non_trainable_vars, x)`, which treats the model as a pure function compatible with `jax.value_and_grad`. Wrap the step in `@jax.jit` for XLA fusion. Swap Keras's built-in optimizers for `optax` to get composable gradient transforms — learning rate warmup, gradient clipping, and per-parameter schedules — without leaving JAX's functional style. Non-trainable state (e.g., BatchNorm running stats) is returned explicitly from `stateless_call` and must be threaded through your loop manually.$escape$,
  $escape$import os; os.environ["KERAS_BACKEND"] = "jax"
import jax, jax.numpy as jnp, keras, optax

class L2Dense(keras.Layer):
    def call(self, x):
        x = keras.layers.Dense(64)(x)
        return x / (jnp.linalg.norm(x, axis=-1, keepdims=True) + 1e-8)

inputs = keras.Input(shape=(128,))
x = L2Dense()(inputs)
outputs = keras.layers.Dense(10, activation="softmax")(x)
model = keras.Model(inputs, outputs)

opt = optax.adam(1e-3)
opt_state = opt.init(model.trainable_variables)

@jax.jit
def train_step(tvars, non_tvars, opt_state, x, y):
    def loss_fn(tvars):
        (preds,), non_tvars_out, _ = model.stateless_call(tvars, non_tvars, x)
        return keras.losses.sparse_categorical_crossentropy(y, preds).mean(), non_tvars_out
    (loss, non_tvars_out), grads = jax.value_and_grad(loss_fn, has_aux=True)(tvars)
    updates, opt_state_new = opt.update(grads, opt_state)
    return loss, optax.apply_updates(tvars, updates), non_tvars_out, opt_state_new$escape$,
