INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'aad75029-4165-4ba1-8d4d-0bfeb2dcec97',
  '00000000-0000-0000-0000-000000000001',
  $escape$JAX Production Export — ONNX Conversion and Serving Considerations$escape$,
  $escape$JAX has no native ONNX exporter — the production path is JAX → TensorFlow (via `jax2tf`) → ONNX (via `tf2onnx`). The critical flag is `enable_xla=False` in `jax2tf.convert`: XLA ops don't lower cleanly to ONNX primitives, so disabling it forces decomposition into standard TF ops that `tf2onnx` understands. Omitting this flag is the most common cause of unsupported op errors during conversion.

Before export, bind your trained params into a single-argument callable — ONNX has no concept of JAX pytree inputs. Use a lambda or `functools.partial` to close over your parameter dict. This sidesteps pytree serialization issues and gives `jax2tf` a clean function signature to trace.

For serving, ONNX Runtime with `CUDAExecutionProvider` works well, but always validate op coverage with `onnxruntime.InferenceSession` before deploying. If you need JAX-native serving, `jax.export.export()` (JAX 0.4.24+) emits StableHLO directly — the better path for TPU/XLA serving pipelines, though it requires a StableHLO-capable runtime like the one in JAX itself or XLA-enabled TF Serving. For Flax models, always unbind `model.apply` from `params` before either export path.$escape$,
  $escape$import jax.numpy as jnp
from jax.experimental import jax2tf
import tensorflow as tf
import tf2onnx

# Trained params from your JAX/Flax model
# Bind params to get a single-input callable (ONNX has no pytree concept)
bound_fn = lambda x: model.apply(params, x)

# enable_xla=False is required — XLA ops don't map to ONNX primitives
tf_fn = jax2tf.convert(bound_fn, enable_xla=False)
tf_concrete = tf.function(
    tf_fn,
    input_signature=[tf.TensorSpec([None, 128], tf.float32)]
).get_concrete_function()

# Export to ONNX via tf2onnx
onnx_proto, _ = tf2onnx.convert.from_concrete_function(tf_concrete)
with open("model.onnx", "wb") as f:
    f.write(onnx_proto.SerializeToString())$escape$,
  $escape$python$escape$,
